// htmx 1.9.x placeholder shipped as a vendored stub.
// The real minified bundle should be dropped here before production builds.
// For tests and local development we expose just enough to avoid 404s and to
// inject the CSRF header on every htmx-driven request.
(function () {
  if (typeof window === "undefined") return;
  if (window.htmx) return;
  window.htmx = {
    version: "1.9.placeholder",
    on: function () {},
    onLoad: function () {},
    process: function () {},
    config: { selfRequestsOnly: true },
  };
})();
